internal.get("/polis/reminders", rbacMiddleware("polis"), async (c) => {
  try {
    const now = /* @__PURE__ */ new Date();
    const allPolis = await db.select({
      id: polisData.id,
      polisNumber: polisData.polisNumber,
      createdAt: polisData.createdAt,
      premiumAmount: polisData.premiumAmount,
      productName: polisData.productName,
      status: polisData.status,
      agentId: polisData.agentId,
      nasabahId: polisData.nasabahId
    }).from(polisData).where(eq(polisData.status, "approved"));
    const reminders = [];
    for (const p2 of allPolis) {
      if (!p2.createdAt) continue;
      const anniversaryDate = new Date(p2.createdAt);
      anniversaryDate.setFullYear(anniversaryDate.getFullYear() + 1);
      const daysUntilAnniversary = Math.ceil((anniversaryDate.getTime() - now.getTime()) / (1e3 * 60 * 60 * 24));
      let months = (now.getFullYear() - p2.createdAt.getFullYear()) * 12;
      months -= p2.createdAt.getMonth();
      months += now.getMonth();
      const monthsLeft = 12 - months;
      const [nasabahProfile] = await db.select({ fullName: profiles.fullName }).from(profiles).where(eq(profiles.userId, p2.nasabahId)).limit(1);
      const nasabahName = nasabahProfile?.fullName || "Unknown";
      const [agentProfile] = await db.select({ fullName: profiles.fullName }).from(profiles).where(eq(profiles.userId, p2.agentId)).limit(1);
      const agentName = agentProfile?.fullName || "Unknown";
      if (daysUntilAnniversary <= 7 && daysUntilAnniversary > 0) {
        reminders.push({
          id: p2.id,
          polisNumber: p2.polisNumber,
          nasabahName,
          agentName,
          daysLeft: daysUntilAnniversary,
          type: "h7",
          message: `Polis #${p2.polisNumber} atas nama ${nasabahName} jatuh tempo dalam ${daysUntilAnniversary} hari.`,
          premiumAmount: p2.premiumAmount,
          productName: p2.productName
        });
      }
      if (monthsLeft === 1 || monthsLeft === 2 || monthsLeft === 3) {
        reminders.push({
          id: p2.id,
          polisNumber: p2.polisNumber,
          nasabahName,
          agentName,
          daysLeft: Math.ceil(daysUntilAnniversary),
          type: "monthly",
          message: `Polis #${p2.polisNumber} atas nama ${nasabahName} jatuh tempo dalam ${Math.ceil(daysUntilAnniversary)} hari.`,
          premiumAmount: p2.premiumAmount,
          productName: p2.productName
        });
      }
    }
    reminders.sort((a2, b) => a2.daysLeft - b.daysLeft);
    return c.json({ success: true, data: reminders });
  } catch (error48) {
    console.error("Polis Reminders Error:", error48);
    return c.json({ success: false, message: "Failed to fetch polis reminders" }, 500);
  }
});
